void *malloc(size_t size) {
    if (size == 0) return NULL;
    size = ALIGN16(size);

    block_header_t *curr = free_list;
    block_header_t *prev = NULL;

    while (curr) {
        if (curr->free && curr->size >= size) {
            curr->free = 0;
            return (void *)(curr + 1);
        }
        prev = curr;
        curr = curr->next;
    }

    size_t needed = sizeof(block_header_t) + size;
    if (heap_offset + needed > sizeof(heap)) return NULL;

    block_header_t *block = (block_header_t *)(heap + heap_offset);
    heap_offset += needed;
    block->size = size;
    block->free = 0;
    block->next = NULL;

    if (prev) prev->next = block;
    else free_list = block;

    return (void *)(block + 1);
}

void free(void *ptr) {
    if (!ptr) return;
    block_header_t *block = ((block_header_t *)ptr) - 1;
    block->free = 1;
}

