static FILE _stdout_f = {1, 1, 0, 0};
static FILE _stderr_f = {2, 1, 0, 0};
FILE *stdin_file = &_stdin_f;
FILE *stdout_file = &_stdout_f;
FILE *stderr_file = &_stderr_f;

FILE *fopen(const char *path, const char *mode) {
    int flags = 0;
    if (mode[0] == 'r') flags = 0;
    else if (mode[0] == 'w') flags = 1 | 64 | 512;
    else if (mode[0] == 'a') flags = 1 | 64 | 1024;
    if (mode[1] == '+') flags = 2;
    int fd = sys_open(path, flags, 0666);
    if (fd < 0) return NULL;
    FILE *fp = malloc(sizeof(FILE));
    if (!fp) { sys_close(fd); return NULL; }
    fp->fd = fd;
    fp->flags = flags;
    fp->eof = 0;
    fp->error = 0;
    return fp;
}

int fclose(FILE *fp) {
    if (!fp || fp == stdin_file || fp == stdout_file || fp == stderr_file) return -1;
    int r = sys_close(fp->fd);
    free(fp);
    return r;
}

size_t fread(void *ptr, size_t size, size_t nmemb, FILE *fp) {
    if (!fp || size == 0 || nmemb == 0) return 0;
    size_t total = size * nmemb;
    int n = sys_read(fp->fd, ptr, total);
    if (n <= 0) { fp->eof = 1; return 0; }
    return n / size;
}

size_t fwrite(const void *ptr, size_t size, size_t nmemb, FILE *fp) {
    if (!fp || size == 0 || nmemb == 0) return 0;
    size_t total = size * nmemb;
    int n = sys_write(fp->fd, ptr, total);
    if (n <= 0) { fp->error = 1; return 0; }
    return n / size;
}

int fseek(FILE *fp, long offset, int whence) {
    if (!fp) return -1;
    fp->eof = 0;
    return sys_lseek(fp->fd, offset, whence);
}

long ftell(FILE *fp) {
    if (!fp) return -1;
    return sys_lseek(fp->fd, 0, 1);
}

int fflush(FILE *fp) { return 0; }
int feof(FILE *fp) { return fp ? fp->eof : 1; }

int fgetc(FILE *fp) {
    unsigned char c;
    if (sys_read(fp->fd, &c, 1) != 1) { fp->eof = 1; return -1; }
    return c;
}

int getchar(void) { return fgetc(stdin_file); }
int ungetc(int c, FILE *fp) { return -1; }

char *fgets(char *s, int size, FILE *fp) {
    int i = 0;
    if (size <= 0) return NULL;
    while (i < size - 1) {
        int c = fgetc(fp);
        if (c < 0) break;
        s[i++] = (char)c;
        if (c == '\n') break;
    }
    s[i] = 0;
    return i > 0 ? s : NULL;
}

int fputs(const char *s, FILE *fp) {
    size_t len = strlen(s);
    return sys_write(fp->fd, s, len);
}

int puts(const char *s) {
    int r = fputs(s, stdout_file);
    char nl = '\n';
    sys_write(1, &nl, 1);
    return r;
}

void perror(const char *s) {
    if (s) { fputs(s, stderr_file); fputs(": ", stderr_file); }
    fputs("error\n", stderr_file);
}

int sscanf(const char *str, const char *fmt, ...) { return 0; }

// vsnprintf
static int _print_itoa(char *buf, long val, int base, int uppercase, int width, int pad_zero, int sign) {
    char tmp[32];
    const char *digits = uppercase ? "0123456789ABCDEF" : "0123456789abcdef";
    unsigned long uval;
    int neg = 0;
    if (sign && val < 0) { neg = 1; uval = (unsigned long)(-(long)val); }
    else uval = (unsigned long)val;
    int i = 0;
    if (uval == 0) tmp[i++] = '0';
    else while (uval > 0) { tmp[i++] = digits[uval % base]; uval /= base; }
    int len = i;
    if (neg) len++;
    char *out = buf;
    if (width > 0 && !pad_zero) { for (int j = len; j < width; j++) *out++ = ' '; }
    if (neg) *out++ = '-';
    if (width > 0 && pad_zero) { for (int j = len; j < width; j++) *out++ = '0'; }
    while (i > 0) *out++ = tmp[--i];
    return out - buf;
}

int vsnprintf(char *str, size_t size, const char *fmt, va_list ap) {
    char *out = str;
    char *end = str + size - 1;
    if (size == 0) return 0;
    while (*fmt && out < end) {
        if (*fmt != '%') { *out++ = *fmt++; continue; }
        fmt++;
        int pad_zero = 0, width = 0, long_flag = 0;
        if (*fmt == '0') { pad_zero = 1; fmt++; }
        while (*fmt >= '0' && *fmt <= '9') { width = width * 10 + (*fmt - '0'); fmt++; }
        if (*fmt == 'l') { long_flag = 1; fmt++; }
        switch (*fmt) {
            case 'd': case 'i': {
                long val = long_flag ? va_arg(ap, long) : (long)va_arg(ap, int);
                out += _print_itoa(out, val, 10, 0, width, pad_zero, 1);
                break;
            }
            case 'u': {
                unsigned long val = long_flag ? va_arg(ap, unsigned long) : (unsigned long)va_arg(ap, unsigned int);
                out += _print_itoa(out, (long)val, 10, 0, width, pad_zero, 0);
                break;
            }
            case 'x': case 'X': {
                unsigned long val = long_flag ? va_arg(ap, unsigned long) : (unsigned long)va_arg(ap, unsigned int);
                out += _print_itoa(out, (long)val, 16, *fmt == 'X', width, pad_zero, 0);
                break;
            }
            case 'o': {
                unsigned long val = long_flag ? va_arg(ap, unsigned long) : (unsigned long)va_arg(ap, unsigned int);
                out += _print_itoa(out, (long)val, 8, 0, width, pad_zero, 0);
                break;
            }
            case 'p': {
                unsigned long val = (unsigned long)(size_t)va_arg(ap, void *);
                *out++ = '0'; if (out < end) *out++ = 'x';
                out += _print_itoa(out, (long)val, 16, 0, 8, 1, 0);
                break;
            }
            case 's': {
                const char *s = va_arg(ap, const char *);
                if (!s) s = "(null)";
                while (*s && out < end) *out++ = *s++;
                break;
            }
            case 'c': { *out++ = (char)va_arg(ap, int); break; }
            case '%': { *out++ = '%'; break; }
            default: *out++ = '%'; if (out < end) *out++ = *fmt; break;
        }
        fmt++;
    }
    *out = 0;
    return out - str;
}

int sprintf(char *str, const char *fmt, ...) {
    va_list ap; va_start(ap, fmt);
    int r = vsnprintf(str, 0x7FFFFFFF, fmt, ap);
    va_end(ap); return r;
}

int snprintf(char *str, size_t size, const char *fmt, ...) {
    va_list ap; va_start(ap, fmt);
    int r = vsnprintf(str, size, fmt, ap);
    va_end(ap); return r;
}

int printf(const char *fmt, ...) {
    char buf[1024];
    va_list ap; va_start(ap, fmt);
    int r = vsnprintf(buf, sizeof(buf), fmt, ap);
    va_end(ap);
    sys_write(1, buf, r);
    return r;
}

int fprintf(FILE *fp, const char *fmt, ...) {
    char buf[1024];
    va_list ap; va_start(ap, fmt);
    int r = vsnprintf(buf, sizeof(buf), fmt, ap);
    va_end(ap);
    sys_write(fp->fd, buf, r);
    return r;
}
